mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM TRIP t
    LEFT JOIN TRIP_MEMBER tm
      ON tm.trip_id = t.trip_id
     AND tm.user_id = #{userId}
     AND tm.invite_status = 'ACCEPTED'
    WHERE t.trip_id = #{tripId}
      AND (t.owner_user_id = #{userId} OR tm.trip_member_id IS NOT NULL)
)

SELECT EXISTS (
    SELECT 1
    FROM PLACE
    WHERE place_id = #{placeId}
)

mapper.delete:
DELETE FROM SCHEDULE_ITEM
WHERE trip_id = #{tripId}
  AND schedule_item_id = #{scheduleItemId}
